public class MessageContextCaptureHandler implements SOAPHandler<SOAPMessageContext> {
    @Override
    public Set<QName> getHeaders() {
        return Collections.emptySet();
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.FALSE.equals(outbound)) {
            org.apache.cxf.message.Message cxfMessage = org.apache.cxf.phase.PhaseInterceptorChain.getCurrentMessage();
            if (cxfMessage != null) {
                cxfMessage.getExchange().put(BindingMessageContextHolder.class, new BindingMessageContextHolder(context));
            }
        }
        return true;
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }
}